// User Management
package user

import (
	"context"

	"github.com/arminguenther/xeruspower-go/idl"
	"github.com/arminguenther/xeruspower-go/usermgmt/role"
)

// SNMPv3 security level
type SnmpV3SecLevel int

const (
	NO_AUTH_NO_PRIV SnmpV3SecLevel = iota // No authentication and no privacy protocol
	AUTH_NO_PRIV                          // Use authentication but no privacy protocol
	AUTH_PRIV                             // Use both, authentication and privacy protocol
)

// SNMPv3 authentication protocol
type SnmpV3AuthProto int

const (
	MD5    SnmpV3AuthProto = iota // Use HMAC-MD5-96 for authentication
	SHA1                          // Use HMAC-SHA1-96 for authentication
	SHA224                        // Use HMAC-SHA224-128 for authentication
	SHA256                        // Use HMAC-SHA256-160 for authentication
	SHA384                        // Use HMAC-SHA384-256 for authentication
	SHA512                        // Use HMAC-SHA512-384 for authentication
)

// SNMPv3 privacy protocol
type SnmpV3PrivProto int

const (
	DES         SnmpV3PrivProto = iota // Use DES encryption
	AES128                             // Use AES128 encryption
	AES192                             // Use AES192 encryption with Blumenthal key extension algorithm
	AES256                             // Use AES256 encryption with Blumenthal key extension algorithm
	AES192_3DES                        // Use AES192 encryption with 3DES/Reeder key extension algorithm
	AES256_3DES                        // Use AES256 encryption with 3DES/Reeder key extension algorithm
)

// SNMPv3 settings
type SnmpV3Settings struct {
	Enabled                           bool            // SNMPv3 enabled
	SecLevel                          SnmpV3SecLevel  // Security level
	AuthProtocol                      SnmpV3AuthProto // Authentication protocol
	UsePasswordAsAuthPassphrase       bool            // Use account password for SNMPv3 authentication
	HaveAuthPassphrase                bool            // Authentication passphrase present
	AuthPassphrase                    string          // Authentication passphrase; cannot be read back
	PrivProtocol                      SnmpV3PrivProto // Privacy protocol
	UseAuthPassphraseAsPrivPassphrase bool            // Use authentication passphrase as privacy passphrase
	HavePrivPassphrase                bool            // Privacy passphrase present
	PrivPassphrase                    string          // Privacy passphrase; cannot be read back
}

// Auxiliary user information
type AuxInfo struct {
	Fullname  string // Full name
	Telephone string // Telephone number
	EMail     string // Email address
}

// Preferred display unit for temperature sensors
type TemperatureEnum int

const (
	DEG_C TemperatureEnum = iota // Degrees Celsius
	DEG_F                        // Degrees Fahrenheit
)

// Preferred display unit for length measurements, e.g. device altitude
type LengthEnum int

const (
	METER LengthEnum = iota // Meters
	FEET                    // Feet
)

// Preferred display unit for (air) pressure sensors
type PressureEnum int

const (
	PASCAL PressureEnum = iota // Pascal
	PSI                        // pound-force per square inch
)

// User preferences
type Preferences struct {
	TemperatureUnit TemperatureEnum // Display unit for temperature sensors
	LengthUnit      LengthEnum      // Display unit for length measurements
	PressureUnit    PressureEnum    // Display unit for pressure sensors
}

// User information
type Info struct {
	Enabled            bool           // true if the account is enabled
	Locked             bool           // true if the account cannot be deleted
	Blocked            bool           // true if the account is blocked due to failed logins
	NeedPasswordChange bool           // true to force a password change on the next login
	AuxInfo            AuxInfo        // Auxiliary user information
	SnmpV3Settings     SnmpV3Settings // SNMPv3 settings
	SshPublicKey       string         // Public key for SSH access
	Preferences        Preferences    // User preferences
	RoleIds            []int32        // List of role ids for this account
}

// User Capabilities
// Describe if certain operations can be performed for user.
// May require according privileges.
type Capabilities struct {
	CanSetPassword    bool // User password is modifiable
	CanSetPreferences bool // User preferences are modifiable
}

const (
	ERR_PASSWORD_UNCHANGED          int32 = 1  // The new password must differ from the old password
	ERR_PASSWORD_EMPTY              int32 = 2  // The password must not be empty
	ERR_PASSWORD_TOO_SHORT          int32 = 3  // The password is too short
	ERR_PASSWORD_TOO_LONG           int32 = 4  // The password is too long
	ERR_PASSWORD_CTRL_CHARS         int32 = 5  // The password must not contain control characters
	ERR_PASSWORD_NEED_LOWER         int32 = 6  // The password must contain at least one lower-case character
	ERR_PASSWORD_NEED_UPPER         int32 = 7  // The password must contain at least one upper-case character
	ERR_PASSWORD_NEED_NUMERIC       int32 = 8  // The password must contain at least one numeric character
	ERR_PASSWORD_NEED_SPECIAL       int32 = 9  // The password must contain at least one special character
	ERR_PASSWORD_IN_HISTORY         int32 = 10 // The password is already in the password history
	ERR_PASSWORD_TOO_SHORT_FOR_SNMP int32 = 11 // The password is too short to be used as SNMPv3 passphrase
	ERR_INVALID_ARGUMENT            int32 = 12 // Invalid arguments
	ERR_WRONG_PASSWORD              int32 = 13 // The passed-in password was wrong
	ERR_SSH_PUBKEY_DATA_TOO_LARGE   int32 = 14 // The ssh public key data is too large.
	ERR_SSH_PUBKEY_INVALID          int32 = 15 // The ssh public key is invalid.
	ERR_SSH_PUBKEY_NOT_SUPPORTED    int32 = 16 // The ssh public key is not supported.
	ERR_SSH_RSA_PUBKEY_TOO_SHORT    int32 = 17 // The ssh RSA public key is too short.
)

// User interface
type User interface {
	idl.Object

	// Get user information.
	//
	//	@return User information
	GetInfo(ctx context.Context) (Info, error)

	// Set the account password.
	//
	//	@param password The new password
	//
	//	@return  0 OK
	//	@return  1 The new password has to differ from old password.
	//	@return  2 The password must not be empty.
	//	@return  3 The password is too short.
	//	@return  4 The password is too long.
	//	@return  5 The password must not contain control characters.
	//	@return  6 The password has to contain at least one lower case
	//	           character.
	//	@return  7 The password has to contain at least one upper case
	//	           character.
	//	@return  8 The password has to contain at least one numeric
	//	           character.
	//	@return  9 The password has to contain at least one printable
	//	           special character.
	//	@return 10 The password already is in history.
	//	@return 11 SNMPv3 USM is activated for the user and the
	//	           password shall be used as auth passphrase. For this
	//	           case, the password is too short (must be at least 8
	//	           characters).
	SetAccountPassword(ctx context.Context, password string) (int32, error)

	// Update user information.
	//
	//	@param password The new password; empty to leave unchanged
	//	@param info     The new user information
	//
	//	@return  0 OK
	//	@return  1 The new password has to differ from old password.
	//	@return  3 The password is too short.
	//	@return  4 The password is too long.
	//	@return  5 The password must not contain control characters.
	//	@return  6 The password has to contain at least one lower case
	//	           character.
	//	@return  7 The password has to contain at least one upper case
	//	           character.
	//	@return  8 The password has to contain at least one numeric
	//	           character.
	//	@return  9 The password has to contain at least one printable
	//	           special character.
	//	@return 10 The password already is in history.
	//	@return 11 SNMPv3 USM is activated for the user and the
	//	           password shall be used as auth passphrase. For this
	//	           case, the password is too short (must be at least 8
	//	           characters).
	//	@return 12 An argument is invalid or out of range
	//	@return 13 The password passed in as SNMPv3 authentication pass
	//	           phrase was wrong.
	//	@return 14 The ssh public key data is too large.
	//	@return 15 The ssh public key is invalid.
	//	@return 16 The ssh public key is not supported.
	//	@return 17 The ssh RSA public key is too short.
	UpdateAccountFull(ctx context.Context, password string, info Info) (int32, error)

	// Get information and a list of granted privileges for a user.
	//
	//	@param info        User information
	//	@param privileges  List of granted privileges
	GetInfoAndPrivileges(ctx context.Context) (info Info, privileges []role.Privilege, err error)

	// Sets the user preferences.
	//
	//	@param prefs                 User Preferences
	//
	//	@return 0                    OK
	//	@return ERR_INVALID_ARGUMENT An argument is invalid or out of range
	SetPreferences(ctx context.Context, prefs Preferences) (int32, error)

	// Gets the user capabilities.
	//
	//	@return  capabilities
	GetCapabilities(ctx context.Context) (Capabilities, error)
}
